// Normaliza el payload del webhook, genera ID/fecha, arma los HTML de correo
// y deja el PDF listo como binario (para Google Drive) y como base64 (para Resend).
const raw = $input.first().json;
const b = raw.body || raw;

const cliente = b.cliente || {};
const proyecto = b.proyecto || {};
const cart = Array.isArray(b.cart) ? b.cart : [];
const moneda = b.moneda || 'MXN';
const simbolo = moneda;
const subtotal = Number(b.subtotal || 0);
const iva = Number(b.iva || 0);
const total = Number(b.total || 0);
const metodoPago = b.metodoPago || '';
const tipoCambio = Number(b.tipoCambio || 0);

const correos = Array.isArray(cliente.correos)
  ? cliente.correos.filter(Boolean)
  : (Array.isArray(b.correos) ? b.correos.filter(Boolean) : []);

if (correos.length === 0) {
  throw new Error('El payload no incluye ningun correo de cliente (cliente.correos vacio).');
}

const cotizacionId = b.cotizacionId || ('COT-' + Date.now());
const timestamp = new Date().toISOString();
const fechaMX = new Date().toLocaleDateString('es-MX');
const fechaVigencia = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toLocaleDateString('es-MX');

// PDF: quitar el prefijo data: si viniera incluido.
let pdfBase64 = b.pdfBase64 || '';
pdfBase64 = pdfBase64.replace(/^data:application\/pdf(;base64)?,/, '');

const nombreArchivo = b.nombreArchivo
  || ('Cotizacion_' + String(cliente.nombreCompleto || 'Cliente').replace(/\s+/g, '_') + '_' + fechaMX.replace(/\//g, '-') + '.pdf');

const METODO = {
  tarjeta_credito: 'Tarjeta de Credito',
  tarjeta_debito: 'Tarjeta de Debito',
  contado: 'Contado',
  cheque: 'Cheque',
  transferencia: 'Transferencia',
  credito: 'Credito',
};
const metodoLabel = METODO[metodoPago] || metodoPago || '-';

const fmt = (n) => '$' + Number(n || 0).toLocaleString('es-MX', { maximumFractionDigits: 2 });

const filasProductos = cart.map((it) => {
  const precio = (it.product && it.product.precio) || 0;
  const cantidad = it.cantidad || 0;
  const descuento = it.descuento || 0;
  const pu = precio * (1 - descuento / 100);
  const imp = pu * cantidad;
  const nombre = (it.product && it.product.nombre) || '';
  const nota = it.notas ? '<br><span style="color:#666;font-size:11px">Nota: ' + it.notas + '</span>' : '';
  return '<tr>'
    + '<td style="padding:10px;text-align:left;border-bottom:1px solid #e5e7eb">' + nombre + nota + '</td>'
    + '<td style="padding:10px;text-align:center;border-bottom:1px solid #e5e7eb">' + cantidad + '</td>'
    + '<td style="padding:10px;text-align:right;border-bottom:1px solid #e5e7eb">' + fmt(pu) + '</td>'
    + '<td style="padding:10px;text-align:right;border-bottom:1px solid #e5e7eb">' + fmt(imp) + '</td>'
    + '</tr>';
}).join('');

const asunto = 'Cotizacion - ' + (proyecto.titulo || cliente.nombreCompleto || cotizacionId);

const htmlCliente = ''
+ '<!DOCTYPE html><html><head><meta charset="utf-8"></head>'
+ '<body style="font-family:Arial,sans-serif;color:#333;margin:0;padding:0;background:#f4f5f7">'
+ '<div style="max-width:640px;margin:0 auto;padding:24px">'
+ '<div style="background:#0055a5;color:#fff;padding:24px;text-align:center;border-radius:8px 8px 0 0">'
+ '<h1 style="margin:0;font-size:22px">' + (proyecto.titulo || 'Cotizacion') + '</h1>'
+ '<p style="margin:6px 0 0;opacity:.9">HIMAYA Sistemas - Seguridad Electronica</p></div>'
+ '<div style="background:#fff;padding:24px;border:1px solid #e5e7eb;border-top:none">'
+ '<h2 style="margin-top:0;color:#0055a5">Hola, ' + (cliente.nombreCompleto || '') + '</h2>'
+ '<p>Adjunto encontrara su cotizacion en PDF con el detalle completo. Aqui un resumen:</p>'
+ (proyecto.descripcion ? '<p style="color:#555">' + proyecto.descripcion + '</p>' : '')
+ '<div style="background:#f3f4f6;padding:14px;border-radius:6px;margin:16px 0">'
+ '<p style="margin:4px 0"><strong>' + (cliente.nombreCompleto || '') + '</strong></p>'
+ (cliente.empresa ? '<p style="margin:4px 0">Empresa: ' + cliente.empresa + '</p>' : '')
+ (cliente.rfc ? '<p style="margin:4px 0">RFC: ' + cliente.rfc + '</p>' : '')
+ (cliente.telefono ? '<p style="margin:4px 0">Telefono: ' + cliente.telefono + '</p>' : '')
+ '<p style="margin:4px 0">Metodo de pago: ' + metodoLabel + '</p></div>'
+ '<table style="width:100%;border-collapse:collapse;margin:16px 0">'
+ '<thead><tr style="background:#0055a5;color:#fff">'
+ '<th style="padding:10px;text-align:left">Descripcion</th>'
+ '<th style="padding:10px;text-align:center">Cant.</th>'
+ '<th style="padding:10px;text-align:right">P. Unitario</th>'
+ '<th style="padding:10px;text-align:right">Subtotal</th></tr></thead>'
+ '<tbody>' + filasProductos + '</tbody></table>'
+ '<div style="text-align:right;margin:16px 0">'
+ '<div style="margin:6px 0"><strong>Subtotal:</strong> ' + fmt(subtotal) + ' ' + simbolo + '</div>'
+ '<div style="margin:6px 0"><strong>IVA (16%):</strong> ' + fmt(iva) + ' ' + simbolo + '</div>'
+ '<div style="display:inline-block;margin-top:8px;padding:10px 16px;background:#0055a5;color:#fff;border-radius:6px;font-size:18px"><strong>TOTAL: ' + fmt(total) + ' ' + simbolo + '</strong></div>'
+ '</div>'
+ '<p style="color:#555">Vigencia: 30 dias naturales (hasta el ' + fechaVigencia + '). Los precios pueden variar despues de la vigencia.</p>'
+ '<p>Cualquier duda, respondemos con gusto por este medio o por WhatsApp.</p>'
+ '</div>'
+ '<div style="text-align:center;color:#888;font-size:12px;padding:16px">Cotizacion ' + cotizacionId + ' - (c) ' + new Date().getFullYear() + ' HIMAYA Sistemas</div>'
+ '</div></body></html>';

const htmlInterno = ''
+ '<div style="font-family:Arial,sans-serif;color:#222">'
+ '<h2 style="color:#0055a5">Nueva cotizacion generada</h2>'
+ '<table style="border-collapse:collapse">'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>ID</strong></td><td>' + cotizacionId + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Fecha</strong></td><td>' + fechaMX + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Cliente</strong></td><td>' + (cliente.nombreCompleto || '') + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Empresa</strong></td><td>' + (cliente.empresa || '-') + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Correos</strong></td><td>' + correos.join(', ') + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Telefono</strong></td><td>' + (cliente.telefono || '-') + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Proyecto</strong></td><td>' + (proyecto.titulo || '-') + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Metodo pago</strong></td><td>' + metodoLabel + '</td></tr>'
+ '<tr><td style="padding:4px 12px 4px 0"><strong>Total</strong></td><td>' + fmt(total) + ' ' + simbolo + '</td></tr>'
+ '</table></div>';

const productosJson = JSON.stringify(cart);
const emailStr = correos.join(', ');

const salida = {
  cotizacionId, timestamp, fechaMX, fechaVigencia,
  cliente, proyecto, cart, moneda, simbolo, tipoCambio,
  subtotal, iva, total, metodoPago, metodoLabel,
  correos, emailStr, productosJson, notas: (proyecto.descripcion || proyecto.titulo || ''),
  nombreArchivo, pdfBase64, tienePdf: pdfBase64.length > 0,
  asunto, htmlCliente, htmlInterno,
};

const item = { json: salida };
if (pdfBase64) {
  item.binary = { pdf: { data: pdfBase64, mimeType: 'application/pdf', fileName: nombreArchivo } };
}
return [item];

// Reune el estado de cada paso (los nodos usan onError:continue) y arma la respuesta JSON.
const p = $('Prep').first().json;

function ok(nodeName) {
  try {
    const it = $(nodeName).first();
    if (!it) return false;
    if (it.json && (it.json.error || it.error)) return false;
    return true;
  } catch (e) {
    return false;
  }
}

const emailSent = ok('Resend - Correo Cliente');
const sheetsUpdated = ok('Google Sheets - Append');
const driveSaved = ok('Google Drive - Guardar PDF');
const adminNotified = ok('Resend - Notificacion Interna');

return [{
  json: {
    success: emailSent || sheetsUpdated,
    cotizacionId: p.cotizacionId,
    timestamp: p.timestamp,
    emailSent,
    sheetsUpdated,
    driveSaved,
    adminNotified,
    pdfAdjuntado: p.tienePdf,
    destinatarios: p.correos,
  },
}];
